// AI Agent: Analyze customer query with live store context
const data = $input.item.json;

// Extract customer message from webhook payload
const customerMessage = data.body?.message || data.message || '';
const customerEmail = data.body?.customer_email || data.customer_email || '';
const customerName = data.body?.customer_name || data.customer_name || 'Customer';
const sessionId = data.body?.session_id || `SESSION-${Date.now()}`;

// Extract store data
const orders = data.orders || [];
const inventoryLevels = data.inventory_levels || [];

// --- Intent Classification Logic ---
const msg = customerMessage.toLowerCase();

let intent = 'GENERAL_SUPPORT';
let confidence = 0.6;

if (msg.includes('refund') || msg.includes('return') || msg.includes('money back') || msg.includes('cancel')) {
  intent = 'REFUND_REQUEST';
  confidence = 0.95;
} else if (msg.includes('order') || msg.includes('tracking') || msg.includes('shipped') || msg.includes('delivery') || msg.includes('where is')) {
  intent = 'ORDER_INQUIRY';
  confidence = 0.90;
} else if (msg.includes('stock') || msg.includes('available') || msg.includes('in stock') || msg.includes('inventory') || msg.includes('restock')) {
  intent = 'INVENTORY_CHECK';
  confidence = 0.88;
} else if (msg.includes('price') || msg.includes('discount') || msg.includes('coupon') || msg.includes('sale') || msg.includes('deal')) {
  intent = 'PRICING_INQUIRY';
  confidence = 0.85;
}

// --- Extract relevant order info ---
const latestOrder = orders.length > 0 ? orders[0] : null;
const orderSummary = latestOrder ? {
  order_number: latestOrder.order_number || 'N/A',
  financial_status: latestOrder.financial_status || 'N/A',
  fulfillment_status: latestOrder.fulfillment_status || 'unfulfilled',
  total_price: latestOrder.total_price || '0.00',
  currency: latestOrder.currency || 'USD',
  created_at: latestOrder.created_at || 'N/A',
  tracking_number: latestOrder.fulfillments?.[0]?.tracking_number || null,
  line_items: (latestOrder.line_items || []).map(i => ({ title: i.title, quantity: i.quantity, price: i.price }))
} : null;

// --- Low stock detection ---
const lowStockItems = inventoryLevels.filter(item => (item.available || 0) <= 5).map(item => ({
  inventory_item_id: item.inventory_item_id,
  available: item.available,
  location_id: item.location_id
}));

// --- Eligibility checks ---
const isRefundEligible = latestOrder && 
  latestOrder.financial_status === 'paid' && 
  latestOrder.fulfillment_status !== 'fulfilled';

const daysSinceOrder = latestOrder ? 
  Math.floor((Date.now() - new Date(latestOrder.created_at).getTime()) / (1000 * 60 * 60 * 24)) : null;

const refundWindow = 30; // days
const withinRefundWindow = daysSinceOrder !== null && daysSinceOrder <= refundWindow;

// --- Generate AI response text ---
let aiResponse = '';
let requiresEscalation = false;
let actionRequired = null;

switch (intent) {
  case 'ORDER_INQUIRY':
    if (orderSummary) {
      const trackingInfo = orderSummary.tracking_number 
        ? `Your tracking number is **${orderSummary.tracking_number}**.` 
        : 'Your order is being prepared and a tracking number will be assigned soon.';
      aiResponse = `Hi ${customerName}! 👋 I found your most recent order #${orderSummary.order_number}.\n\n` +
        `📦 **Order Status:** ${orderSummary.fulfillment_status}\n` +
        `💳 **Payment:** ${orderSummary.financial_status}\n` +
        `💰 **Total:** ${orderSummary.currency} ${orderSummary.total_price}\n` +
        `📅 **Placed:** ${new Date(orderSummary.created_at).toLocaleDateString()}\n\n` +
        `${trackingInfo}\n\nIs there anything else I can help you with?`;
    } else {
      aiResponse = `Hi ${customerName}! I couldn't find any recent orders linked to your email. Could you double-check your order email or provide your order number? I'm happy to look it up! 😊`;
    }
    break;

  case 'REFUND_REQUEST':
    if (orderSummary && isRefundEligible && withinRefundWindow) {
      actionRequired = 'PROCESS_REFUND';
      aiResponse = `Hi ${customerName}! I've reviewed your order #${orderSummary.order_number} and I'm processing your refund request now. ✅\n\n` +
        `💰 **Refund Amount:** ${orderSummary.currency} ${orderSummary.total_price}\n` +
        `⏱️ **Processing Time:** 3–5 business days\n\nYou'll receive a confirmation email shortly. I'm sorry for any inconvenience!`;
    } else if (orderSummary && !withinRefundWindow) {
      requiresEscalation = true;
      aiResponse = `Hi ${customerName}! I've reviewed your order #${orderSummary.order_number}. Unfortunately, it's been ${daysSinceOrder} days since your order was placed, which is outside our standard ${refundWindow}-day return window.\n\nI'm escalating this to our team for a manual review. You'll hear back within 24 hours! 🙏`;
    } else {
      requiresEscalation = true;
      aiResponse = `Hi ${customerName}! I couldn't automatically process your refund request — this may need manual review by our team. I'm escalating this now and you'll hear back within 24 hours. Sorry for the trouble!`;
    }
    break;

  case 'INVENTORY_CHECK':
    if (lowStockItems.length > 0) {
      actionRequired = 'SEND_STOCK_ALERT';
      aiResponse = `Hi ${customerName}! Great question about availability. Some items in our catalog are running low and may sell out soon — I'd recommend grabbing them quickly! 🔥\n\nFor specific product availability, could you share the product name or SKU? I'll give you a precise answer!`;
    } else {
      aiResponse = `Hi ${customerName}! Great news — our inventory looks well-stocked right now. 🎉 Could you share the specific product you're interested in? I'll confirm exact availability for you!`;
    }
    break;

  case 'PRICING_INQUIRY':
    aiResponse = `Hi ${customerName}! Thanks for reaching out about pricing. 😊 Our current promotions and deals are always listed on our website. For exclusive discounts, signing up for our newsletter gets you 10% off your first order!\n\nIs there a specific product you're looking at? I can check if there are any active deals on it!`;
    break;

  default:
    aiResponse = `Hi ${customerName}! Thanks for reaching out to our support team. 😊\n\nI'm here to help with:\n• 📦 Order tracking and status\n• 💰 Refunds and returns\n• 📊 Product availability\n• 🏷️ Pricing and promotions\n\nCould you tell me more about what you need? I'll get it sorted right away!`;
}

// --- Timestamp ---
const timestamp = new Date().toISOString();
const ticketId = `TKT-${Date.now()}`;

return {
  json: {
    // Ticket identity
    ticketId,
    sessionId,
    timestamp,

    // Customer info
    customerName,
    customerEmail,
    customerMessage,

    // AI Analysis
    intent,
    confidence,
    aiResponse,

    // Actions
    actionRequired,
    requiresEscalation,

    // Order context
    orderSummary,
    hasOrder: !!orderSummary,

    // Inventory context
    lowStockItems,
    lowStockCount: lowStockItems.length,
    hasLowStock: lowStockItems.length > 0,

    // Refund eligibility
    isRefundEligible: isRefundEligible && withinRefundWindow,
    daysSinceOrder
  }
};

