// Build the final HTML email response and Slack summary
const report = $input.item.json;

const intentEmoji = {
  'ORDER_INQUIRY': '📦',
  'REFUND_REQUEST': '💰',
  'INVENTORY_CHECK': '📊',
  'PRICING_INQUIRY': '🏷️',
  'GENERAL_SUPPORT': '💬'
}[report.intent] || '💬';

const statusColor = report.requiresEscalation ? '#f59e0b' 
  : report.actionRequired === 'PROCESS_REFUND' ? '#22c55e' 
  : '#3b82f6';

// Build HTML email response
const emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Support Reply — ${report.ticketId}</title>
  <style>
    body { font-family: Arial, sans-serif; color: #1e293b; margin: 0; padding: 0; background: #f8fafc; }
    .container { max-width: 600px; margin: 24px auto; background: white; border-radius: 12px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
    .header { background: #0f172a; color: white; padding: 24px; }
    .header h1 { margin: 0 0 4px 0; font-size: 18px; }
    .header p { margin: 0; opacity: 0.6; font-size: 12px; }
    .badge { display: inline-block; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; background: ${statusColor}; color: white; margin-top: 10px; }
    .body { padding: 24px; }
    .message-box { background: #f1f5f9; border-radius: 8px; padding: 16px; margin-bottom: 16px; white-space: pre-line; line-height: 1.6; }
    .order-card { border: 1px solid #e2e8f0; border-radius: 8px; padding: 16px; margin-bottom: 16px; }
    .order-card h3 { margin: 0 0 8px 0; font-size: 14px; color: #64748b; }
    .order-row { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid #f1f5f9; font-size: 13px; }
    .footer { background: #f8fafc; padding: 16px 24px; text-align: center; font-size: 11px; color: #94a3b8; border-top: 1px solid #e2e8f0; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>${intentEmoji} Support Reply from Our Team</h1>
      <p>Ticket ID: ${report.ticketId} &nbsp;|&nbsp; ${new Date(report.timestamp).toLocaleString()}</p>
      <div class="badge">${report.intent.replace('_', ' ')}</div>
    </div>
    <div class="body">
      <div class="message-box">${report.aiResponse}</div>
      ${report.orderSummary ? `
      <div class="order-card">
        <h3>📦 Your Order Details</h3>
        <div class="order-row"><span>Order Number</span><span>#${report.orderSummary.order_number}</span></div>
        <div class="order-row"><span>Status</span><span>${report.orderSummary.fulfillment_status}</span></div>
        <div class="order-row"><span>Payment</span><span>${report.orderSummary.financial_status}</span></div>
        <div class="order-row"><span>Total</span><span>${report.orderSummary.currency} ${report.orderSummary.total_price}</span></div>
        ${report.orderSummary.tracking_number ? `<div class="order-row"><span>Tracking</span><span>${report.orderSummary.tracking_number}</span></div>` : ''}
      </div>` : ''}
    </div>
    <div class="footer">This is an automated response powered by AI &nbsp;|&nbsp; Reply to this email to speak with a human agent</div>
  </div>
</body>
</html>`;

// Slack summary message
const slackSummary = `${intentEmoji} *[${report.ticketId}] ${report.intent.replace(/_/g, ' ')}*\n\n` +
  `*Customer:* ${report.customerName} (${report.customerEmail})\n` +
  `*Message:* ${report.customerMessage}\n` +
  `*AI Confidence:* ${Math.round(report.confidence * 100)}%\n` +
  `*Action Taken:* ${report.actionRequired || 'Response sent'}\n` +
  `*Escalated:* ${report.requiresEscalation ? 'Yes ⚠️' : 'No ✅'}`;

return {
  json: {
    ...report,
    emailHtml,
    slackSummary,
    emailSubject: `${intentEmoji} [${report.ticketId}] Re: Your support request — ${report.intent.replace(/_/g, ' ')}`,
    shouldSendEmail: !!report.customerEmail,
    shouldNotifySlack: true
  }
};

// Log successful AI agent interaction and track statistics
const timestamp = new Date().toISOString();
const report = $input.item.json;

console.log(`✅ AI AGENT SUCCESS: Ticket ${report.ticketId} | Intent: ${report.intent} | Customer: ${report.customerEmail} | Escalated: ${report.requiresEscalation} | Time: ${timestamp}`);

// Cumulative statistics
const stats = $getWorkflowStaticData('global').agentStats || {
  totalTickets: 0,
  byIntent: {},
  refundsProcessed: 0,
  stockAlertsTriggered: 0,
  escalations: 0,
  lastProcessed: null
};

stats.totalTickets++;
stats.byIntent[report.intent] = (stats.byIntent[report.intent] || 0) + 1;
if (report.actionRequired === 'PROCESS_REFUND') stats.refundsProcessed++;
if (report.actionRequired === 'SEND_STOCK_ALERT') stats.stockAlertsTriggered++;
if (report.requiresEscalation) stats.escalations++;
stats.lastProcessed = timestamp;

$getWorkflowStaticData('global').agentStats = stats;

return {
  json: {
    success: true,
    ticketId: report.ticketId,
    intent: report.intent,
    customerEmail: report.customerEmail,
    actionTaken: report.actionRequired || 'RESPONSE_SENT',
    escalated: report.requiresEscalation,
    timestamp,
    cumulativeStats: stats
  }
};
